class Solution:
    def connect(self, root: 'Optional[Node]') -> 'Optional[Node]':
        dummy = Node(0)
        prev = dummy
        cur = root
        while cur:
            while cur:
                if cur.left:
                    prev.next = cur.left
                    prev = prev.next
                if cur.right:
                    prev.next = cur.right
                    prev = prev.next
                cur = cur.next
            cur = dummy.next
            dummy.next = None
            prev = dummy
        return root

