class Solution {
public:
    Node* connect(Node* root) {
        Node dummy(0);
        Node* prev = &dummy;
        Node* cur = root;
        while (cur) {
            while (cur) {
                if (cur->left) {
                    prev->next = cur->left;
                    prev = prev->next;
                }
                if (cur->right) {
                    prev->next = cur->right;
                    prev = prev->next;
                }
                cur = cur->next;
            }
            cur = dummy.next;
            dummy.next = nullptr;
            prev = &dummy;
        }
        return root;
    }
};
